using System;
using System.Collections.Generic;
using UnityEngine;
using UnityEngine.InputSystem;
using UnityEngine.SceneManagement;

/// <summary>
/// Painel de testes/cheats de Animals.
///
/// - Abre/fecha com F1.
/// - Funciona apenas no Unity Editor e em Development Builds.
/// - É criado automaticamente; não precisa de Canvas nem de GameObject manual.
/// - Usa exclusivamente os sistemas já existentes no projecto.
/// - O sistema de desafios é apenas mostrado, nunca alterado por este painel.
///
/// Colocar em: Assets/Scripts/Debug/AnimalsDebugPanel.cs
/// </summary>
public class AnimalsDebugPanel : MonoBehaviour
{
    private static AnimalsDebugPanel _instance;

    private readonly string[] _tabs =
    {
        "Rápido", "Animais", "Itens", "Upgrades", "Missões",
        "Progresso", "Transporte", "Mundo", "Inimigos", "Save/Variáveis", "Habilidades"
    };

    private Rect _windowRect;
    private Vector2 _scroll;
    private int _tab;
    private bool _isOpen;
    private bool _pausedByPanel;
    private bool _previousCursorVisible;
    private CursorLockMode _previousCursorLock;

    private GUIStyle _titleStyle;
    private GUIStyle _sectionStyle;
    private GUIStyle _boxStyle;
    private GUIStyle _mutedStyle;
    private GUIStyle _dangerStyle;
    private bool _stylesReady;

    private string _search = "";
    private string _status = "Painel pronto.";
    private float _statusUntil;

    private SaveData _sessionSnapshot;
    private int _manualSlot;

    private bool _godMode;
    private bool _transformCheat;
    private bool _transformDefaultsCaptured;
    private bool _originalRequireGrounded;
    private float _originalTransformCooldown;

    private Action _pendingDangerAction;
    private string _pendingDangerLabel;

    private readonly Dictionary<string, int> _spawnSelection = new Dictionary<string, int>();
    private readonly Dictionary<string, string> _variableBuffers = new Dictionary<string, string>();

    private string _newVariableName = "";
    private int _newVariableType;
    private string _newVariableValue = "";

    private string _pendingFallbackScene;

    private static readonly string[] VariableTypeNames = { "Bool", "Int", "Float", "String" };

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.AfterSceneLoad)]
    private static void EnsureExists()
    {
#if UNITY_EDITOR || DEVELOPMENT_BUILD
        if (_instance != null) return;

        var existing = FindObjectOfType<AnimalsDebugPanel>();
        if (existing != null)
        {
            _instance = existing;
            return;
        }

        var go = new GameObject("Animals Debug Panel");
        go.AddComponent<AnimalsDebugPanel>();
#endif
    }

    private void Awake()
    {
#if !UNITY_EDITOR && !DEVELOPMENT_BUILD
        Destroy(gameObject);
        return;
#else
        if (_instance != null && _instance != this)
        {
            Destroy(gameObject);
            return;
        }

        _instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);

        float width = Mathf.Min(1180f, Screen.width - 30f);
        float height = Mathf.Min(820f, Screen.height - 30f);
        _windowRect = new Rect((Screen.width - width) * 0.5f, (Screen.height - height) * 0.5f, width, height);
#endif
    }

    private void Update()
    {
#if UNITY_EDITOR || DEVELOPMENT_BUILD
        if (_godMode) ApplyGodModeToCurrentPlayer(true);
        if (_transformCheat) ApplyTransformCheatToCurrentPlayer();

        var keyboard = Keyboard.current;
        if (keyboard == null) return;

        if (keyboard.f1Key.wasPressedThisFrame)
            SetOpen(!_isOpen);
        else if (_isOpen && keyboard.escapeKey.wasPressedThisFrame)
            SetOpen(false);
#endif
    }

    private void OnDestroy()
    {
        SceneManager.sceneLoaded -= HandleFallbackSpawnAfterTravel;
        ApplyGodModeToCurrentPlayer(false);
        RestoreTransformDefaults();

        if (_isOpen)
            RestorePauseAndCursor();

        if (_instance == this)
            _instance = null;
    }

    private void SetOpen(bool value)
    {
        if (_isOpen == value) return;
        _isOpen = value;

        if (_isOpen)
        {
            _previousCursorVisible = Cursor.visible;
            _previousCursorLock = Cursor.lockState;

            Cursor.visible = true;
            Cursor.lockState = CursorLockMode.None;

            if (!GamePauseUtil.IsPaused)
            {
                GamePauseUtil.Pause();
                _pausedByPanel = true;
            }
            else
            {
                _pausedByPanel = false;
            }

            ClampWindowToScreen();
        }
        else
        {
            RestorePauseAndCursor();
            _pendingDangerAction = null;
            _pendingDangerLabel = null;
        }
    }

    private void RestorePauseAndCursor()
    {
        if (_pausedByPanel && GamePauseUtil.IsPaused)
            GamePauseUtil.Resume();

        _pausedByPanel = false;
        Cursor.visible = _previousCursorVisible;
        Cursor.lockState = _previousCursorLock;
    }

    private void OnGUI()
    {
#if UNITY_EDITOR || DEVELOPMENT_BUILD
        if (!_isOpen) return;

        EnsureStyles();
        ClampWindowToScreen();
        _windowRect = GUI.Window(GetInstanceID(), _windowRect, DrawWindow, "");
#endif
    }

    private void EnsureStyles()
    {
        if (_stylesReady) return;

        _titleStyle = new GUIStyle(GUI.skin.label)
        {
            fontSize = 20,
            fontStyle = FontStyle.Bold,
            alignment = TextAnchor.MiddleLeft
        };

        _sectionStyle = new GUIStyle(GUI.skin.label)
        {
            fontSize = 15,
            fontStyle = FontStyle.Bold
        };

        _boxStyle = new GUIStyle(GUI.skin.box)
        {
            padding = new RectOffset(10, 10, 8, 8),
            margin = new RectOffset(3, 3, 4, 4)
        };

        _mutedStyle = new GUIStyle(GUI.skin.label)
        {
            wordWrap = true,
            fontSize = 11
        };
        _mutedStyle.normal.textColor = new Color(0.72f, 0.76f, 0.78f);

        _dangerStyle = new GUIStyle(GUI.skin.label)
        {
            fontStyle = FontStyle.Bold,
            wordWrap = true
        };
        _dangerStyle.normal.textColor = new Color(1f, 0.55f, 0.45f);

        _stylesReady = true;
    }

    private void ClampWindowToScreen()
    {
        float maxWidth = Mathf.Max(480f, Screen.width - 20f);
        float maxHeight = Mathf.Max(360f, Screen.height - 20f);

        _windowRect.width = Mathf.Min(_windowRect.width, maxWidth);
        _windowRect.height = Mathf.Min(_windowRect.height, maxHeight);
        _windowRect.x = Mathf.Clamp(_windowRect.x, 0f, Mathf.Max(0f, Screen.width - _windowRect.width));
        _windowRect.y = Mathf.Clamp(_windowRect.y, 0f, Mathf.Max(0f, Screen.height - _windowRect.height));
    }

    private void DrawWindow(int id)
    {
        GUILayout.BeginVertical();

        GUILayout.BeginHorizontal();
        GUILayout.Label("🐾 ANIMALS — PAINEL DE TESTES", _titleStyle);
        GUILayout.FlexibleSpace();
        GUILayout.Label($"Cena: {SceneManager.GetActiveScene().name}", GUILayout.MaxWidth(330f));
        if (GUILayout.Button("Fechar (F1)", GUILayout.Width(105f)))
            SetOpen(false);
        GUILayout.EndHorizontal();

        DrawDiagnosticsLine();

        GUILayout.Space(4f);
        _tab = GUILayout.Toolbar(_tab, _tabs, GUILayout.Height(30f));

        GUILayout.BeginHorizontal();
        GUILayout.Label("Pesquisar:", GUILayout.Width(72f));
        _search = GUILayout.TextField(_search ?? "");
        if (GUILayout.Button("Limpar", GUILayout.Width(65f))) _search = "";
        GUILayout.EndHorizontal();

        _scroll = GUILayout.BeginScrollView(_scroll, false, true);
        switch (_tab)
        {
            case 0: DrawQuickTab(); break;
            case 1: DrawAnimalsTab(); break;
            case 2: DrawItemsTab(); break;
            case 3: DrawUpgradesTab(); break;
            case 4: DrawMissionsTab(); break;
            case 5: DrawProgressTab(); break;
            case 6: DrawTransportTab(); break;
            case 7: DrawWorldTab(); break;
            case 8: DrawEnemiesTab(); break;
            case 9: DrawSaveVariablesTab(); break;
            case 10: DrawAbilitiesTab(); break;
        }
        GUILayout.EndScrollView();

        DrawDangerConfirmation();

        GUILayout.Space(3f);
        string statusText = Time.unscaledTime <= _statusUntil ? _status : "F1 abre/fecha. O painel existe apenas no Editor e em Development Builds.";
        GUILayout.Label(statusText, _mutedStyle);

        GUILayout.EndVertical();
        GUI.DragWindow(new Rect(0, 0, _windowRect.width - 120f, 34f));
    }

    private void DrawDiagnosticsLine()
    {
        var progress = PlayerProgress.Instance;
        var db = GameDatabase.Instance;
        var world = WorldState.Instance;
        var form = FindFormSwitcher();

        string progressText = progress != null ? "Progresso ✓" : "Progresso AUSENTE";
        string dbText = db != null ? $"Database ✓ ({db.areas.Count} áreas)" : "GameDatabase AUSENTE";
        string areaText = world != null && world.CurrentArea != null ? world.CurrentArea.displayName : "Área não definida";
        string formText = form != null && form.CurrentForm != null ? form.CurrentForm.displayName : "Íris/sem forma";

        GUILayout.BeginHorizontal(GUI.skin.box);
        GUILayout.Label(progressText);
        GUILayout.Label(dbText);
        GUILayout.Label($"Área: {areaText}");
        GUILayout.Label($"Forma: {formText}");
        GUILayout.EndHorizontal();
    }

    // =====================================================================
    // RÁPIDO
    // =====================================================================

    private void DrawQuickTab()
    {
        var p = PlayerProgress.Instance;
        var db = GameDatabase.Instance;

        Section("Estado da sessão");
        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Criar snapshot temporário")) CreateSessionSnapshot();
        GUI.enabled = _sessionSnapshot != null;
        if (GUILayout.Button("Restaurar snapshot")) RestoreSessionSnapshot();
        GUI.enabled = true;
        GUILayout.EndHorizontal();
        GUILayout.Label("O snapshot é seguro enquanto permaneceres na mesma cena. Antes de viajar, faz também um save manual.", _mutedStyle);

        if (p == null)
        {
            Missing("PlayerProgress.Instance não existe.");
            return;
        }

        Section("Vida");
        GUILayout.BeginHorizontal(_boxStyle);
        GUILayout.Label($"Corações: {p.currentHearts}/{p.maxHearts}", GUILayout.Width(160f));
        if (GUILayout.Button("Curar tudo")) p.Heal(p.maxHearts);
        if (GUILayout.Button("Dano 1")) p.Damage(1);
        if (GUILayout.Button("Matar")) p.Damage(p.currentHearts);
        if (GUILayout.Button("Máx. -1")) SetMaxHearts(p.maxHearts - 1);
        if (GUILayout.Button("Máx. +1")) SetMaxHearts(p.maxHearts + 1);
        if (GUILayout.Button("12 corações")) SetMaxHearts(PlayerProgress.MaxHeartsCap);
        GUILayout.EndHorizontal();

        Section("Recursos — saldo disponível");
        ResourceRow("Sementes", p.sementes,
            delegate { SetSeedBalance(p.sementes - 100); },
            delegate { SetSeedBalance(p.sementes - 10); },
            delegate { SetSeedBalance(p.sementes + 10); },
            delegate { SetSeedBalance(p.sementes + 100); },
            delegate { SetSeedBalance(0); });

        ResourceRow("Runas de Gaia", p.runasDeGaia,
            delegate { SetRunaBalance(p.runasDeGaia - 10); },
            delegate { SetRunaBalance(p.runasDeGaia - 1); },
            delegate { SetRunaBalance(p.runasDeGaia + 1); },
            delegate { SetRunaBalance(p.runasDeGaia + 10); },
            delegate { SetRunaBalance(0); });

        ResourceRow("Brotos de Vida", p.brotosDeVida,
            delegate { p.brotosDeVida = Mathf.Max(0, p.brotosDeVida - 10); },
            delegate { p.brotosDeVida = Mathf.Max(0, p.brotosDeVida - 1); },
            delegate { p.brotosDeVida += 1; },
            delegate { p.brotosDeVida += 10; },
            delegate { p.brotosDeVida = 0; });

        ResourceRow("Fragmentos Vitais", p.fragmentosVitais,
            delegate { p.GiveFragmentosVitais(-10); },
            delegate { p.GiveFragmentosVitais(-1); },
            delegate { p.GiveFragmentosVitais(1); },
            delegate { p.GiveFragmentosVitais(10); },
            delegate { p.fragmentosVitais = 0; });

        GUILayout.Label("Sementes e Runas alteradas aqui mudam apenas o saldo, sem fingir que foram encontradas numa área. Fragmentos adicionados usam a conversão real para corações.", _mutedStyle);

        Section("Cheats momentâneos");
        GUILayout.BeginHorizontal(_boxStyle);
        if (GUILayout.Button(_godMode ? "Invencibilidade: LIGADA" : "Invencibilidade: desligada"))
        {
            _godMode = !_godMode;
            ApplyGodModeToCurrentPlayer(_godMode);
            SetStatus(_godMode ? "Invencibilidade ligada para todos os tipos de dano." : "Invencibilidade desligada.");
        }

        if (GUILayout.Button(_transformCheat ? "Transformação livre: LIGADA" : "Transformação livre: desligada"))
        {
            SetTransformCheat(!_transformCheat);
        }
        GUILayout.EndHorizontal();
        GUILayout.Label("Transformação livre remove a exigência de chão e coloca o cooldown em 0. O fit check e bloqueios de segurança do movimento continuam activos.", _mutedStyle);

        Section("Pacotes rápidos");
        GUI.enabled = db != null;
        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Libertar todos os animais")) FreeAllAnimals();
        if (GUILayout.Button("Dar todos os itens")) GiveAllItems();
        if (GUILayout.Button("Desbloquear todos os upgrades")) UnlockAllUpgrades();
        if (GUILayout.Button("Abrir todas as áreas")) OpenAllAreas();
        GUILayout.EndHorizontal();

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Completar todas as missões")) CompleteAllMissions();
        if (GUILayout.Button("Revelar totais dos mundos")) RevealAllWorldTotals();
        if (GUILayout.Button("Obter todos os emblemas")) ObtainAllEmblems();
        GUILayout.EndHorizontal();
        GUI.enabled = true;

        Section("Limpeza rápida");
        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Retirar todos os itens")) AskDanger("Retirar todos os itens do inventário?", ClearAllItems);
        if (GUILayout.Button("Retirar animais extras")) AskDanger("Retirar todos os animais excepto a forma inicial?", RemoveAllExtraAnimals);
        if (GUILayout.Button("Retirar todos os upgrades")) AskDanger("Retirar todos os upgrades e Instintos?", ClearAllUpgrades);
        GUILayout.EndHorizontal();

        Section("Pós-Game / NG+");
        bool isPostGame = p.IsPostGameRewardActive;
        bool isNGPlus   = p.IsNewGamePlus;
        GUILayout.BeginHorizontal(_boxStyle);
        GUILayout.Label($"Recompensa pós-game: {(isPostGame ? "ACTIVA" : "inactiva")}", GUILayout.Width(260f));
        GUILayout.Label($"NG+: {(isNGPlus ? "SIM" : "não")}", GUILayout.Width(100f));
        GUILayout.EndHorizontal();

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Dar recompensa pós-game"))
        {
            var recompId = PlayerProgress.RecompensaPosJogoUpgradeId;
            if (!p.unlockedUpgradeIds.Contains(recompId)) p.unlockedUpgradeIds.Add(recompId);
            if (!p.enabledUpgradeIds.Contains(recompId))  p.enabledUpgradeIds.Add(recompId);
            SetStatus("Recompensa pós-game concedida.");
        }
        if (GUILayout.Button("Retirar recompensa pós-game"))
        {
            p.unlockedUpgradeIds.Remove(PlayerProgress.RecompensaPosJogoUpgradeId);
            p.enabledUpgradeIds.Remove(PlayerProgress.RecompensaPosJogoUpgradeId);
            SetStatus("Recompensa pós-game removida.");
        }
        if (GUILayout.Button("Simular StartNewGamePlus()"))
            AskDanger("Isto vai resetar o progresso (excepto animais libertados, upgrades e emblemas). Continuar?",
                delegate { p.StartNewGamePlus(); SetStatus("NG+ iniciado — recarrega a cena para efeito completo."); });
        GUILayout.EndHorizontal();
        GUILayout.Label("Usa 'Dar recompensa' para activar o pós-game sem cutscene. 'Simular NG+' executa StartNewGamePlus() directamente — faz snapshot antes.", _mutedStyle);
    }

    private void ResourceRow(string label, int value, Action minusLarge, Action minusSmall, Action plusSmall, Action plusLarge, Action zero)
    {
        GUILayout.BeginHorizontal(_boxStyle);
        GUILayout.Label($"{label}: {value}", GUILayout.Width(200f));
        if (GUILayout.Button("− grande", GUILayout.Width(78f))) minusLarge();
        if (GUILayout.Button("−", GUILayout.Width(42f))) minusSmall();
        if (GUILayout.Button("+", GUILayout.Width(42f))) plusSmall();
        if (GUILayout.Button("+ grande", GUILayout.Width(78f))) plusLarge();
        if (GUILayout.Button("Zerar", GUILayout.Width(62f))) zero();
        GUILayout.EndHorizontal();
    }

    // =====================================================================
    // ANIMAIS
    // =====================================================================

    private void DrawAnimalsTab()
    {
        var db = GameDatabase.Instance;
        var p = PlayerProgress.Instance;
        var fs = FindFormSwitcher();

        if (db == null || p == null)
        {
            Missing("GameDatabase ou PlayerProgress não encontrado.");
            return;
        }

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Libertar todos")) FreeAllAnimals();
        if (GUILayout.Button("Retirar extras")) AskDanger("Manter apenas a forma inicial?", RemoveAllExtraAnimals);
        GUILayout.EndHorizontal();

        if (fs == null)
            GUILayout.Label("FormSwitcher não foi encontrado. É possível alterar o progresso, mas não transformar imediatamente.", _dangerStyle);

        foreach (var form in db.animalForms)
        {
            if (form == null || !Matches(form.displayName, form.formId, form.primaryAbility.ToString())) continue;

            bool freed = p.HasFreedAnimal(form);
            bool current = fs != null && fs.CurrentForm == form;
            bool isStartingForm = fs != null && fs.startingForm == form;

            GUILayout.BeginVertical(_boxStyle);
            GUILayout.BeginHorizontal();
            GUILayout.Label($"{form.displayName}  [{form.formId}]", _sectionStyle);
            GUILayout.FlexibleSpace();
            GUILayout.Label(current ? "FORMA ACTUAL" : (freed ? "Libertado" : "Bloqueado"));
            GUILayout.EndHorizontal();

            GUILayout.Label($"Habilidade principal: {form.primaryAbility} | Categorias: {form.categories} | Mundo: {(form.originWorld != null ? form.originWorld.displayName : "—")}", _mutedStyle);

            GUILayout.BeginHorizontal();
            if (!freed)
            {
                if (GUILayout.Button("Libertar")) FreeAnimal(form);
            }
            else if (isStartingForm)
            {
                GUI.enabled = false;
                GUILayout.Button("Forma inicial");
                GUI.enabled = true;
            }
            else
            {
                if (GUILayout.Button("Retirar")) AskDanger($"Retirar {form.displayName}?", delegate { RemoveAnimal(form); });
            }

            GUI.enabled = fs != null;
            if (GUILayout.Button("Transformar agora")) TransformNow(form);
            GUI.enabled = true;
            GUILayout.EndHorizontal();
            GUILayout.EndVertical();
        }
    }

    // =====================================================================
    // ITENS
    // =====================================================================

    private void DrawItemsTab()
    {
        var db = GameDatabase.Instance;
        var p = PlayerProgress.Instance;
        var itemUser = FindPlayerComponent<PlayerItemUser>();

        if (db == null || p == null)
        {
            Missing("GameDatabase ou PlayerProgress não encontrado.");
            return;
        }

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Dar todos")) GiveAllItems();
        if (GUILayout.Button("Retirar todos")) AskDanger("Retirar todos os itens?", ClearAllItems);
        GUILayout.EndHorizontal();

        foreach (var item in db.items)
        {
            if (item == null || !Matches(item.displayName, item.itemId, item.itemType.ToString(), item.effectType.ToString())) continue;

            int quantity = p.GetItemQuantity(item);
            bool special = p.HasCollectedSpecialItem(item);
            bool equipped = p.HasItemEquipped(item);

            GUILayout.BeginVertical(_boxStyle);
            GUILayout.BeginHorizontal();
            GUILayout.Label($"{item.displayName}  [{item.itemId}]", _sectionStyle);
            GUILayout.FlexibleSpace();
            GUILayout.Label($"Quantidade: {quantity}/{item.maxQuantity}");
            GUILayout.EndHorizontal();

            GUILayout.Label($"Tipo: {item.itemType} | Efeito: {item.effectType} | Missão: {(item.isMissionItem ? "sim" : "não")} | Especial registado: {(special ? "sim" : "não")}", _mutedStyle);

            GUILayout.BeginHorizontal();
            if (GUILayout.Button("−1")) p.RemoveItem(item, 1);
            if (GUILayout.Button("+1")) p.AddItem(item, 1);
            if (GUILayout.Button("Máximo")) p.AddItem(item, Mathf.Max(1, item.maxQuantity));
            if (GUILayout.Button("Zerar")) p.RemoveItem(item, int.MaxValue);

            GUI.enabled = quantity > 0 || equipped;
            if (GUILayout.Button(equipped ? "Desequipar" : "Equipar")) p.EquipItem(equipped ? null : item);
            GUI.enabled = true;

            GUI.enabled = itemUser != null && quantity > 0 && item.usableByPlayer;
            if (GUILayout.Button("Usar como no jogo")) UseItemAsGame(item, itemUser);
            GUI.enabled = itemUser != null && item.usableByPlayer;
            if (GUILayout.Button("Testar efeito grátis")) TestItemEffectFree(item, itemUser);
            GUI.enabled = true;

            if (GUILayout.Button(special ? "Permitir recolher novamente" : "Marcar como encontrado"))
            {
                if (special) p.collectedSpecialItemIds.Remove(item.itemId);
                else p.MarkSpecialItemCollected(item.itemId);
            }
            GUILayout.EndHorizontal();
            GUILayout.EndVertical();
        }
    }

    // =====================================================================
    // UPGRADES
    // =====================================================================

    private void DrawUpgradesTab()
    {
        var db = GameDatabase.Instance;
        var p = PlayerProgress.Instance;

        if (db == null || p == null)
        {
            Missing("GameDatabase ou PlayerProgress não encontrado.");
            return;
        }

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Desbloquear todos")) UnlockAllUpgrades();
        if (GUILayout.Button("Retirar todos")) AskDanger("Retirar todos os upgrades?", ClearAllUpgrades);
        GUILayout.EndHorizontal();

        foreach (var upgrade in db.upgrades)
        {
            if (upgrade == null || !Matches(upgrade.displayName, upgrade.upgradeId, upgrade.description)) continue;

            bool unlocked = p.HasUpgrade(upgrade);
            bool enabled = p.IsUpgradeEnabled(upgrade);

            GUILayout.BeginVertical(_boxStyle);
            GUILayout.BeginHorizontal();
            GUILayout.Label($"{upgrade.displayName}  [{upgrade.upgradeId}]", _sectionStyle);
            GUILayout.FlexibleSpace();
            GUILayout.Label(unlocked ? (enabled ? "Desbloqueado e activo" : "Desbloqueado") : "Bloqueado");
            GUILayout.EndHorizontal();
            GUILayout.Label(upgrade.toggleable ? "Instinto: pode ser ligado/desligado." : "Upgrade permanente: fica activo quando desbloqueado.", _mutedStyle);

            GUILayout.BeginHorizontal();
            if (!unlocked)
            {
                if (GUILayout.Button("Desbloquear")) UnlockUpgradeForTest(upgrade);
            }
            else
            {
                if (GUILayout.Button("Retirar")) RemoveUpgrade(upgrade);
            }

            GUI.enabled = unlocked && upgrade.toggleable;
            if (GUILayout.Button(enabled ? "Desligar" : "Ligar")) SetUpgradeEnabledForTest(upgrade, !enabled);
            GUI.enabled = true;
            GUILayout.EndHorizontal();
            GUILayout.EndVertical();
        }
    }

    // =====================================================================
    // MISSÕES
    // =====================================================================

    private void DrawMissionsTab()
    {
        var db = GameDatabase.Instance;
        var manager = MissionManager.Instance;

        if (db == null || manager == null || GameVariables.Instance == null)
        {
            Missing("GameDatabase, MissionManager ou GameVariables não encontrado.");
            return;
        }

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Completar todas")) CompleteAllMissions();
        if (GUILayout.Button("Resetar todas")) AskDanger("Resetar o estado de todas as missões?", ResetAllMissions);
        GUILayout.EndHorizontal();

        foreach (var mission in db.missions)
        {
            if (mission == null || !Matches(mission.displayName, mission.missionId, mission.description, mission.requestedBy)) continue;

            bool started = manager.IsMissionStarted(mission);
            bool completed = manager.IsMissionCompleted(mission);
            string state = completed ? "Concluída" : (started ? "Em curso" : "Não iniciada");

            GUILayout.BeginVertical(_boxStyle);
            GUILayout.BeginHorizontal();
            GUILayout.Label($"{mission.displayName}  [{mission.missionId}]", _sectionStyle);
            GUILayout.FlexibleSpace();
            GUILayout.Label(state);
            GUILayout.EndHorizontal();

            GUILayout.Label($"Tipo: {mission.missionType} | Início: {mission.StartedVariable} | Conclusão: {mission.CompletedVariable}", _mutedStyle);

            GUILayout.BeginHorizontal();
            if (GUILayout.Button("Não iniciada")) SetMissionState(mission, false, false);
            if (GUILayout.Button("Em curso")) SetMissionState(mission, true, false);
            if (GUILayout.Button("Concluída")) SetMissionState(mission, true, true);
            GUILayout.EndHorizontal();
            GUILayout.EndVertical();
        }
    }

    // =====================================================================
    // PROGRESSO POR ÁREA
    // =====================================================================

    private void DrawProgressTab()
    {
        var db = GameDatabase.Instance;
        var p = PlayerProgress.Instance;

        if (db == null || p == null)
        {
            Missing("GameDatabase ou PlayerProgress não encontrado.");
            return;
        }

        GUILayout.Label("Os botões desta aba alteram os contadores permanentes da área. Não dão saldo de Runas/Sementes e não mexem nos desafios.", _mutedStyle);

        var snapshot = new SaveData();
        p.CaptureTo(snapshot);
        var progressById = new Dictionary<string, AreaProgress>();
        if (snapshot.areaProgress != null)
        {
            foreach (var ap in snapshot.areaProgress)
                if (ap != null && !string.IsNullOrEmpty(ap.areaId)) progressById[ap.areaId] = ap;
        }

        foreach (var area in db.areas)
        {
            if (area == null || !Matches(area.displayName, area.areaId, area.sceneName, area.world != null ? area.world.displayName : "")) continue;

            AreaProgress ap;
            if (!progressById.TryGetValue(area.areaId, out ap))
                ap = new AreaProgress { areaId = area.areaId };

            GUILayout.BeginVertical(_boxStyle);
            GUILayout.BeginHorizontal();
            GUILayout.Label($"{area.displayName}  [{area.areaId}]", _sectionStyle);
            GUILayout.FlexibleSpace();
            GUILayout.Label($"Conclusão: {p.GetAreaCompletionPercent(area)}%");
            GUILayout.EndHorizontal();

            GUILayout.Label($"Mundo: {(area.world != null ? area.world.displayName : "—")} | Aberta: {ap.opened} | Visitada: {ap.visited} | Mortes: {ap.deaths}", _mutedStyle);
            GUILayout.Label($"Runas {ap.runasFound}/{area.totalRunas} | NPCs {ap.npcsRescued}/{area.totalNpcsToRescue} | Sussurros {ap.whispersFound}/{area.totalWhispers} | Entregues {ap.whispersDelivered}/{area.totalWhispers} | Baús {ap.chestsFound}/{area.totalChests} | Fragmentos {ap.fragmentsFound}/{area.totalFragments}", _mutedStyle);

            if (area.hasOptionalChallenge)
                GUILayout.Label($"Desafio: descoberto={ap.challengeDiscovered}, concluído={ap.challengeCompleted} — somente leitura enquanto o sistema está incompleto.", _dangerStyle);

            GUILayout.BeginHorizontal();
            if (GUILayout.Button(ap.opened ? "Fechar acesso" : "Abrir acesso")) MutateArea(area, delegate(AreaProgress x) { x.opened = !ap.opened; });
            if (GUILayout.Button(ap.visited ? "Marcar não visitada" : "Marcar visitada")) MutateArea(area, delegate(AreaProgress x) { x.visited = !ap.visited; });
            if (GUILayout.Button("Completar descobertas")) CompleteAreaDiscoveries(area);
            if (GUILayout.Button("Resetar descobertas")) AskDanger($"Resetar descobertas de {area.displayName}?", delegate { ResetAreaDiscoveries(area); });
            GUILayout.EndHorizontal();

            GUILayout.BeginHorizontal();
            SmallCounter("Runas", ap.runasFound, area.totalRunas,
                delegate { ChangeAreaCounter(area, "runas", -1); }, delegate { ChangeAreaCounter(area, "runas", 1); });
            SmallCounter("NPCs", ap.npcsRescued, area.totalNpcsToRescue,
                delegate { ChangeAreaCounter(area, "npcs", -1); }, delegate { ChangeAreaCounter(area, "npcs", 1); });
            SmallCounter("Sussurros", ap.whispersFound, area.totalWhispers,
                delegate { ChangeAreaCounter(area, "whispers", -1); }, delegate { ChangeAreaCounter(area, "whispers", 1); });
            GUILayout.EndHorizontal();

            GUILayout.BeginHorizontal();
            SmallCounter("Entregues", ap.whispersDelivered, area.totalWhispers,
                delegate { ChangeAreaCounter(area, "delivered", -1); }, delegate { ChangeAreaCounter(area, "delivered", 1); });
            SmallCounter("Baús", ap.chestsFound, area.totalChests,
                delegate { ChangeAreaCounter(area, "chests", -1); }, delegate { ChangeAreaCounter(area, "chests", 1); });
            SmallCounter("Fragmentos", ap.fragmentsFound, area.totalFragments,
                delegate { ChangeAreaCounter(area, "fragments", -1); }, delegate { ChangeAreaCounter(area, "fragments", 1); });
            GUILayout.EndHorizontal();

            GUILayout.EndVertical();
        }
    }

    private void SmallCounter(string label, int value, int total, Action minus, Action plus)
    {
        GUILayout.BeginHorizontal(GUI.skin.box);
        GUILayout.Label($"{label}: {value}/{total}", GUILayout.Width(110f));
        if (GUILayout.Button("−", GUILayout.Width(32f))) minus();
        if (GUILayout.Button("+", GUILayout.Width(32f))) plus();
        GUILayout.EndHorizontal();
    }

    // =====================================================================
    // TRANSPORTE
    // =====================================================================

    private void DrawTransportTab()
    {
        var db = GameDatabase.Instance;
        var worldState = WorldState.Instance;
        var progress = PlayerProgress.Instance;

        if (db == null)
        {
            Missing("GameDatabase não encontrado. Cria Resources/GameDatabase.asset e adiciona as áreas.");
            return;
        }

        GUILayout.Label("A viagem usa o sistema real AreaManager → SceneLoader. Ignora bloqueios de acesso, mas marca a área como visitada e pode disparar autosave, exactamente como uma transição normal.", _mutedStyle);
        GUILayout.Label("Para cada área: sceneName precisa de corresponder ao nome no Build Profile. O painel usa o primeiro ponto de entrada por defeito, mas podes escolher outro.", _mutedStyle);

        var listedAreas = new HashSet<AreaData>();

        if (db.worlds != null)
        {
            foreach (var world in db.worlds)
            {
                if (world == null) continue;

                bool anyWorldMatch = Matches(world.displayName, world.worldId);
                bool hasMatchingArea = false;
                if (db.areas != null)
                {
                    foreach (var areaCheck in db.areas)
                    {
                        if (areaCheck != null && areaCheck.world == world && Matches(areaCheck.displayName, areaCheck.areaId, areaCheck.sceneName))
                        {
                            hasMatchingArea = true;
                            break;
                        }
                    }
                }
                if (!anyWorldMatch && !hasMatchingArea) continue;

                Section($"{world.displayName}  [{world.worldId}]");

                if (db.areas == null) continue;
                foreach (var area in db.areas)
                {
                    if (area == null || area.world != world) continue;
                    listedAreas.Add(area);
                    if (!Matches(area.displayName, area.areaId, area.sceneName, world.displayName)) continue;
                    DrawAreaTravelRow(area, worldState, progress);
                }
            }
        }

        bool drewOtherHeader = false;
        if (db.areas != null)
        {
            foreach (var area in db.areas)
            {
                if (area == null || listedAreas.Contains(area)) continue;
                if (!Matches(area.displayName, area.areaId, area.sceneName, area.world != null ? area.world.displayName : "")) continue;

                if (!drewOtherHeader)
                {
                    Section("Outras áreas / mundo não cadastrado no GameDatabase");
                    GUILayout.Label("Estas áreas continuam disponíveis para teste. Se tiverem um mundo atribuído, adiciona também esse WorldData à lista Worlds do GameDatabase.", _mutedStyle);
                    drewOtherHeader = true;
                }

                DrawAreaTravelRow(area, worldState, progress);
            }
        }
    }

    private void DrawAreaTravelRow(AreaData area, WorldState worldState, PlayerProgress progress)
    {
        bool current = worldState != null && worldState.CurrentArea == area;
        bool opened = progress != null && progress.IsOpened(area);
        bool visited = progress != null && progress.HasVisited(area);
        bool validScene = !string.IsNullOrWhiteSpace(area.sceneName) && Application.CanStreamedLevelBeLoaded(area.sceneName);

        int spawnCount = area.spawnPointIds != null ? area.spawnPointIds.Count : 0;
        int selected = GetSpawnSelection(area, spawnCount);
        string selectedSpawn = spawnCount > 0 ? area.spawnPointIds[selected] : "";

        GUILayout.BeginVertical(_boxStyle);
        GUILayout.BeginHorizontal();
        GUILayout.Label($"{area.displayName}  [{area.areaId}]", _sectionStyle);
        GUILayout.FlexibleSpace();
        GUILayout.Label(current ? "ÁREA ACTUAL" : $"Aberta={opened} | Visitada={visited}");
        GUILayout.EndHorizontal();

        GUILayout.Label($"Cena: {(string.IsNullOrEmpty(area.sceneName) ? "NÃO CONFIGURADA" : area.sceneName)} | Entrada: {(string.IsNullOrEmpty(selectedSpawn) ? "primeiro spawn encontrado na cena" : selectedSpawn)}", _mutedStyle);

        GUILayout.BeginHorizontal();
        if (spawnCount > 1)
        {
            if (GUILayout.Button("◀", GUILayout.Width(34f))) SetSpawnSelection(area, selected - 1, spawnCount);
            GUILayout.Label(selectedSpawn, GUILayout.Width(180f));
            if (GUILayout.Button("▶", GUILayout.Width(34f))) SetSpawnSelection(area, selected + 1, spawnCount);
        }
        else if (spawnCount == 1)
        {
            GUILayout.Label($"Spawn: {selectedSpawn}", GUILayout.Width(250f));
        }
        else
        {
            GUILayout.Label("Sem spawnPointIds no AreaData", _dangerStyle, GUILayout.Width(260f));
        }

        bool transportReady = AreaManager.Instance != null && SceneLoader.Instance != null && LoadingScreenController.Instance != null;
        GUI.enabled = validScene && transportReady && !AreaManager.Instance.TransitionPending;
        if (GUILayout.Button(current ? "Recarregar/transportar" : "Viajar para esta área", GUILayout.Height(28f)))
            TravelToArea(area, selectedSpawn);
        GUI.enabled = true;

        if (!validScene)
            GUILayout.Label("Indisponível: sceneName vazio ou cena ausente do Build Profile.", _dangerStyle);
        else if (!transportReady)
            GUILayout.Label("Indisponível: AreaManager, SceneLoader ou LoadingScreenController não foi criado.", _dangerStyle);

        GUILayout.EndHorizontal();
        GUILayout.EndVertical();
    }

    // =====================================================================
    // MUNDO
    // =====================================================================

    private void DrawWorldTab()
    {
        var ws = WorldState.Instance;
        var db = GameDatabase.Instance;
        var p = PlayerProgress.Instance;

        if (ws == null || db == null || p == null)
        {
            Missing("WorldState, GameDatabase ou PlayerProgress não encontrado.");
            return;
        }

        Section("Hora manual");
        GUILayout.BeginHorizontal();
        foreach (TimeOfDay value in Enum.GetValues(typeof(TimeOfDay)))
        {
            if (GUILayout.Button(value.ToString())) ws.SetManualTimeOfDay(value);
        }
        if (GUILayout.Button("Voltar ao ciclo")) ws.DisableManualTimeOfDay();
        GUILayout.EndHorizontal();
        GUILayout.Label($"Actual: {ws.CurrentTimeOfDay} | Manual: {ws.ManualTimeActive}", _mutedStyle);

        Section("Clima manual");
        GUILayout.BeginHorizontal();
        foreach (WeatherType value in Enum.GetValues(typeof(WeatherType)))
        {
            if (GUILayout.Button(value.ToString())) ws.SetManualWeather(value);
        }
        GUILayout.EndHorizontal();
        if (GUILayout.Button("Voltar ao clima normal/anterior")) ws.DisableManualWeather();
        GUILayout.Label($"Actual: {ws.CurrentWeather} | Manual: {ws.ManualWeatherActive}", _mutedStyle);

        Section("Mundos, bosses e vilas");
        foreach (var world in db.worlds)
        {
            if (world == null || !Matches(world.displayName, world.worldId, world.mainVillageId, world.bossId)) continue;

            bool boss = p.HasDefeatedBoss(world);
            bool returning = p.IsReturningAfterBoss(world);
            bool totals = p.AreWorldTotalsDiscovered(world);
            VillagePopulation pop = !string.IsNullOrEmpty(world.mainVillageId) ? ws.GetVillagePopulation(world.mainVillageId) : null;

            GUILayout.BeginVertical(_boxStyle);
            GUILayout.Label($"{world.displayName}  [{world.worldId}]", _sectionStyle);
            GUILayout.Label($"Boss: {(boss ? "derrotado" : "activo")} | Regresso pós-boss: {returning} | Totais revelados: {totals}", _mutedStyle);

            GUILayout.BeginHorizontal();
            if (GUILayout.Button(boss ? "Resetar boss" : "Marcar boss derrotado"))
            {
                if (boss) ResetBoss(world);
                else p.SetBossDefeated(world);
            }
            if (GUILayout.Button(returning ? "Concluir regresso" : "Activar regresso pós-boss"))
            {
                if (returning) p.ClearReturningAfterBoss(world);
                else SetPostBossReturn(world, true);
            }
            if (GUILayout.Button(totals ? "Esconder totais" : "Revelar totais")) SetWorldTotals(world, !totals);
            GUILayout.EndHorizontal();

            if (!string.IsNullOrEmpty(world.mainVillageId))
            {
                int current = pop != null ? pop.current : 0;
                int max = pop != null ? pop.max : 0;
                GUILayout.BeginHorizontal();
                GUILayout.Label($"Vila [{world.mainVillageId}]: {current}/{max}", GUILayout.Width(230f));
                if (GUILayout.Button("− população")) ws.SetVillagePopulation(world.mainVillageId, Mathf.Max(0, current - 1), max);
                if (GUILayout.Button("+ população")) ws.SetVillagePopulation(world.mainVillageId, current + 1, Mathf.Max(max, current + 1));
                if (GUILayout.Button("+ máximo")) ws.SetVillagePopulation(world.mainVillageId, current, max + 1);
                if (GUILayout.Button("Completar")) ws.SetVillagePopulation(world.mainVillageId, max, max);
                if (GUILayout.Button("Resetar")) ws.SetVillagePopulation(world.mainVillageId, 0, max);
                GUILayout.EndHorizontal();
            }

            GUILayout.EndVertical();
        }

        Section("Emblemas");
        foreach (var emblem in db.emblems)
        {
            if (emblem == null || !Matches(emblem.displayName, emblem.emblemId, emblem.conditionDescription)) continue;

            bool heard = !string.IsNullOrEmpty(emblem.heardAboutVariable) && GameVariables.Instance.GetBool(emblem.heardAboutVariable);
            bool obtained = !string.IsNullOrEmpty(emblem.obtainedVariable) && GameVariables.Instance.GetBool(emblem.obtainedVariable);

            GUILayout.BeginHorizontal(_boxStyle);
            GUILayout.Label($"{emblem.displayName} [{emblem.emblemId}]", GUILayout.Width(300f));
            GUILayout.Label(obtained ? "Obtido" : (heard ? "Condição revelada" : "Desconhecido"), GUILayout.Width(150f));
            if (GUILayout.Button("Desconhecido")) SetEmblemState(emblem, false, false);
            if (GUILayout.Button("Revelar")) SetEmblemState(emblem, true, false);
            if (GUILayout.Button("Obter")) SetEmblemState(emblem, true, true);
            GUILayout.EndHorizontal();
        }

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Forçar EmblemManager.CheckAll()"))
        {
            var em = EmblemManager.Instance;
            if (em != null) { em.CheckAll(); SetStatus("EmblemManager.CheckAll() executado."); }
            else SetStatus("EmblemManager não encontrado.");
        }
        GUILayout.EndHorizontal();
        GUILayout.Label("Força a reavaliação de todas as condições de emblema sem esperar por eventos (útil após dar variáveis manualmente).", _mutedStyle);
    }

    // =====================================================================
    // INIMIGOS
    // =====================================================================

    private void DrawEnemiesTab()
    {
        var p = PlayerProgress.Instance;
        var enemies = FindObjectsOfType<EnemyHealth>(true);

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Matar todos activos"))
        {
            foreach (var enemy in enemies)
                if (enemy != null && enemy.gameObject.activeInHierarchy) enemy.Kill();
            SetStatus("Todos os inimigos activos foram neutralizados.");
        }
        if (GUILayout.Button("Curar/resetar todos"))
        {
            foreach (var respawn in EnemyRespawn.All)
                if (respawn != null) respawn.ResetEnemy();
            foreach (var enemy in enemies)
                if (enemy != null) enemy.ResetHealth();
            SetStatus("Inimigos restaurados.");
        }
        if (p != null && GUILayout.Button("Limpar derrotas permanentes"))
            AskDanger("Permitir que inimigos especiais derrotados reapareçam?", delegate { p.defeatedEnemyIds.Clear(); });
        GUILayout.EndHorizontal();

        GUILayout.Label($"Inimigos encontrados nesta cena: {enemies.Length}", _mutedStyle);

        foreach (var enemy in enemies)
        {
            if (enemy == null) continue;
            var controller = enemy.GetComponent<EnemyController>();
            string display = controller != null && controller.Data != null ? controller.Data.displayName : enemy.name;
            string id = controller != null ? controller.EnemyInstanceId : "—";
            if (!Matches(display, id, enemy.name)) continue;

            GUILayout.BeginHorizontal(_boxStyle);
            GUILayout.Label($"{display} [{id}]", GUILayout.Width(300f));
            GUILayout.Label($"HP {enemy.CurrentHealth}/{enemy.MaxHealth}", GUILayout.Width(90f));
            GUILayout.Label(controller != null ? controller.State.ToString() : "sem controller", GUILayout.Width(110f));
            if (GUILayout.Button("Dano 1")) enemy.TakeDamage(1);
            if (GUILayout.Button("Matar")) enemy.Kill();
            if (GUILayout.Button("Curar")) enemy.ResetHealth();
            if (GUILayout.Button("Ir até")) TeleportPlayerTo(enemy.transform.position);
            GUILayout.EndHorizontal();
        }
    }

