    private void DrawSaveVariablesTab()
    {
        var save = SaveManager.Instance;
        var p = PlayerProgress.Instance;
        var vars = GameVariables.Instance;

        Section("Save");
        if (save == null)
        {
            Missing("SaveManager não encontrado.");
        }
        else
        {
            GUILayout.BeginHorizontal();
            if (GUILayout.Button("Autosave agora")) SetStatus(save.SaveAutosave() ? "Autosave gravado." : "Falha ao gravar autosave.");

            GUILayout.Label("Slot manual:", GUILayout.Width(85f));
            if (GUILayout.Button("−", GUILayout.Width(32f))) _manualSlot = Mathf.Max(0, _manualSlot - 1);
            GUILayout.Label((_manualSlot + 1).ToString(), GUILayout.Width(30f));
            if (GUILayout.Button("+", GUILayout.Width(32f))) _manualSlot = Mathf.Min(SaveManager.MaxManualSlots - 1, _manualSlot + 1);
            if (GUILayout.Button("Gravar slot")) SetStatus(save.SaveToManualSlot(_manualSlot) ? $"Slot {_manualSlot + 1} gravado." : "Falha ao gravar slot.");
            GUI.enabled = save.HasManualSave(_manualSlot);
            if (GUILayout.Button("Apagar slot")) AskDanger($"Apagar o slot manual {_manualSlot + 1}?", delegate { save.DeleteManualSlot(_manualSlot); });
            GUI.enabled = true;
            GUILayout.EndHorizontal();
        }

        Section("Acessibilidade (teste rápido)");
        var settings = GameSettings.Instance;
        if (settings == null)
        {
            GUILayout.Label("GameSettings não encontrado.", _mutedStyle);
        }
        else
        {
            GUILayout.BeginHorizontal(_boxStyle);
            bool shake = settings.ScreenShakeEnabled;
            if (GUILayout.Button($"Screen Shake: {(shake ? "Ligado" : "desligado")}", GUILayout.Width(210f)))
            {
                settings.SetScreenShakeEnabled(!shake);
                SetStatus($"Screen shake {(!shake ? "ligado" : "desligado")}.");
            }
            bool reduced = settings.ReducedFlashes;
            if (GUILayout.Button($"Reduced Flashes: {(reduced ? "Ligado" : "desligado")}", GUILayout.Width(225f)))
            {
                settings.SetReducedFlashes(!reduced);
                SetStatus($"Reduced flashes {(!reduced ? "ligado" : "desligado")}.");
            }
            GUILayout.Label("Gravado em PlayerPrefs pelo GameSettings.", _mutedStyle);
            GUILayout.EndHorizontal();
        }

        Section("Estado persistente");
        if (p != null)
        {
            GUILayout.BeginHorizontal();
            GUILayout.Label($"Pickups recolhidos: {p.collectedPickupIds.Count}", GUILayout.Width(190f));
            if (GUILayout.Button("Limpar IDs de pickups")) AskDanger("Permitir que todos os pickups apareçam novamente após recarregar as cenas?", delegate { p.collectedPickupIds.Clear(); });
            GUILayout.EndHorizontal();

            GUILayout.BeginHorizontal();
            GUILayout.Label($"Itens especiais registados: {p.collectedSpecialItemIds.Count}", GUILayout.Width(190f));
            if (GUILayout.Button("Limpar registos especiais")) AskDanger("Permitir novamente drops/itens únicos?", delegate { p.collectedSpecialItemIds.Clear(); });
            GUILayout.EndHorizontal();

            GUILayout.BeginHorizontal();
            GUILayout.Label($"Inimigos permanentes derrotados: {p.defeatedEnemyIds.Count}", GUILayout.Width(250f));
            if (GUILayout.Button("Limpar derrotas")) AskDanger("Limpar derrotas permanentes?", delegate { p.defeatedEnemyIds.Clear(); });
            GUILayout.EndHorizontal();

            if (GUILayout.Button("RESETAR TODO O PROGRESSO DA SESSÃO"))
                AskDanger("Resetar PlayerProgress, GameVariables e WorldState para o estado inicial configurado no Inspector?", ResetRuntimeProgress);
        }

        Section("Variáveis globais");
        if (vars == null)
        {
            Missing("GameVariables não encontrado.");
            return;
        }

        var data = new SaveData();
        vars.CaptureTo(data);

        if (data.globalVariables != null)
        {
            foreach (var variable in data.globalVariables)
            {
                if (variable == null || !Matches(variable.variableName, variable.type.ToString())) continue;
                DrawVariableRow(vars, variable);
            }
        }

        Section("Criar/definir variável");
        GUILayout.BeginHorizontal(_boxStyle);
        _newVariableName = GUILayout.TextField(_newVariableName ?? "", GUILayout.MinWidth(180f));
        _newVariableType = GUILayout.SelectionGrid(_newVariableType, VariableTypeNames, 4, GUILayout.Width(260f));
        _newVariableValue = GUILayout.TextField(_newVariableValue ?? "", GUILayout.MinWidth(140f));
        if (GUILayout.Button("Definir", GUILayout.Width(80f))) CreateOrSetVariable();
        GUILayout.EndHorizontal();
        GUILayout.Label("Formato do valor: Bool = true/false; Int = número inteiro; Float = número decimal; String = texto livre.", _mutedStyle);
    }

    private void DrawVariableRow(GameVariables vars, GameVariable variable)
    {
        GUILayout.BeginHorizontal(_boxStyle);
        GUILayout.Label(variable.variableName, GUILayout.Width(270f));
        GUILayout.Label(variable.type.ToString(), GUILayout.Width(55f));

        switch (variable.type)
        {
            case VariableType.Bool:
                GUILayout.Label(variable.boolValue.ToString(), GUILayout.Width(90f));
                if (GUILayout.Button("Alternar", GUILayout.Width(75f))) vars.SetBool(variable.variableName, !variable.boolValue);
                break;

            case VariableType.Int:
                GUILayout.Label(variable.intValue.ToString(), GUILayout.Width(90f));
                if (GUILayout.Button("−1", GUILayout.Width(45f))) vars.SetInt(variable.variableName, variable.intValue - 1);
                if (GUILayout.Button("+1", GUILayout.Width(45f))) vars.SetInt(variable.variableName, variable.intValue + 1);
                if (GUILayout.Button("0", GUILayout.Width(40f))) vars.SetInt(variable.variableName, 0);
                break;

            case VariableType.Float:
                GUILayout.Label(variable.floatValue.ToString("0.###"), GUILayout.Width(90f));
                if (GUILayout.Button("−0,5", GUILayout.Width(55f))) vars.SetFloat(variable.variableName, variable.floatValue - 0.5f);
                if (GUILayout.Button("+0,5", GUILayout.Width(55f))) vars.SetFloat(variable.variableName, variable.floatValue + 0.5f);
                if (GUILayout.Button("0", GUILayout.Width(40f))) vars.SetFloat(variable.variableName, 0f);
                break;

            case VariableType.String:
                string buffer;
                if (!_variableBuffers.TryGetValue(variable.variableName, out buffer)) buffer = variable.stringValue ?? "";
                buffer = GUILayout.TextField(buffer, GUILayout.MinWidth(160f));
                _variableBuffers[variable.variableName] = buffer;
                if (GUILayout.Button("Aplicar", GUILayout.Width(65f))) vars.SetString(variable.variableName, buffer);
                break;
        }

        GUILayout.EndHorizontal();
    }

    // =====================================================================
    // HABILIDADES
    // =====================================================================

    /// <summary>
    /// Aba "Habilidades": lista todos os componentes IAbility (e IActiveAbility)
    /// presentes no player — independentemente da forma actual — e permite
    /// Activar/Soltar/Cancelar e zerar cooldowns para teste manual. Útil para
    /// validar Roll/Charge/Dash/etc. sem depender de input real ou de esperar
    /// cooldowns (ver Tarefa #4 — RollAbility/ChargeAbility).
    /// </summary>
    private void DrawAbilitiesTab()
    {
        var player = FindPlayer();
        if (player == null)
        {
            Missing("Player com tag 'Player' não encontrado.");
            return;
        }

        var abilities = player.GetComponents<IAbility>();
        if (abilities == null || abilities.Length == 0)
        {
            Missing("Nenhum componente IAbility encontrado no player.");
            return;
        }

        GUILayout.Label("Activa/solta/cancela cada habilidade directamente, e permite zerar cooldowns para testar sem esperar. CanActivate ainda reflecte os requisitos próprios de cada habilidade (forma, chão, bloqueio de movimento, etc.) — \"Activar\" pode não ter efeito visível se esses requisitos não estiverem reunidos.", _mutedStyle);

        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Zerar todos os cooldowns")) ResetAllCooldowns(abilities);
        if (GUILayout.Button("Cancelar todas (Dialogue)")) CancelAllAbilities(abilities);
        GUILayout.EndHorizontal();

        foreach (var ability in abilities)
        {
            if (ability == null) continue;

            var component = ability as Component;
            string name = component != null ? component.GetType().Name : ability.GetType().Name;
            if (!Matches(name)) continue;

            var active = ability as IActiveAbility;

            GUILayout.BeginVertical(_boxStyle);
            GUILayout.BeginHorizontal();
            GUILayout.Label(name, _sectionStyle);
            GUILayout.FlexibleSpace();
            GUILayout.Label(ability.IsActive ? "ACTIVA" : "inactiva", GUILayout.Width(80f));
            GUILayout.EndHorizontal();

            if (active != null)
            {
                string cooldownText = active.CooldownDuration > 0f
                    ? $"Cooldown: {active.CooldownRemaining:0.0}/{active.CooldownDuration:0.0}s"
                    : "Sem cooldown próprio";
                GUILayout.Label($"{cooldownText} | CanActivate = {active.CanActivate}", _mutedStyle);
            }

            GUILayout.BeginHorizontal();
            if (GUILayout.Button("Activar")) ability.Activate();
            if (GUILayout.Button("Soltar")) ability.Release();
            if (GUILayout.Button("Cancelar")) ability.Cancel(AbilityCancelReason.Dialogue);
            GUI.enabled = active != null && active.CooldownDuration > 0f;
            if (GUILayout.Button("Zerar cooldown")) active.ResetCooldown();
            GUI.enabled = true;
            GUILayout.EndHorizontal();
            GUILayout.EndVertical();
        }
    }

