        FreeAnimal(form);
        fs.ApplyFormImmediate(form);
        SetStatus($"Transformação forçada: {form.displayName}.");
    }

    private void RemoveAnimal(AnimalFormData form)
    {
        var p = PlayerProgress.Instance;
        var fs = FindFormSwitcher();
        if (p == null || form == null) return;

        if (fs != null && fs.startingForm == form)
        {
            SetStatus("A forma inicial não pode ser retirada pelo painel.");
            return;
        }

        if (fs != null && fs.CurrentForm == form)
        {
            AnimalFormData fallback = fs.startingForm;
            if (fallback == null)
            {
                foreach (var candidate in fs.unlockedForms)
                {
                    if (candidate != null && candidate != form)
                    {
                        fallback = candidate;
                        break;
                    }
                }
            }

            if (fallback != null) fs.ApplyFormImmediate(fallback);
        }

        p.freedAnimalIds.Remove(form.formId);

        if (fs != null)
        {
            fs.unlockedForms.RemoveAll(delegate(AnimalFormData x) { return x == null || x == form || x.formId == form.formId; });
            if (fs.startingForm != null && !fs.unlockedForms.Contains(fs.startingForm))
                fs.unlockedForms.Insert(0, fs.startingForm);
        }

        SetStatus($"{form.displayName} retirado.");
    }

    private void RemoveAllExtraAnimals()
    {
        var p = PlayerProgress.Instance;
        var fs = FindFormSwitcher();
        if (p == null) return;

        AnimalFormData starting = fs != null ? fs.startingForm : null;
        p.freedAnimalIds.Clear();
        if (starting != null) p.FreeAnimal(starting);

        if (fs != null)
        {
            fs.unlockedForms.Clear();
            if (starting != null)
            {
                fs.unlockedForms.Add(starting);
                fs.ApplyFormImmediate(starting);
            }
        }

        SetStatus("Animais extras retirados; forma inicial preservada quando configurada.");
    }

