    private void MutateArea(AreaData area, Action<AreaProgress> mutation)
    {
        var p = PlayerProgress.Instance;
        if (p == null || area == null || mutation == null) return;

        var data = new SaveData();
        p.CaptureTo(data);

        AreaProgress target = null;
        foreach (var ap in data.areaProgress)
        {
            if (ap != null && ap.areaId == area.areaId)
            {
                target = ap;
                break;
            }
        }

        if (target == null)
        {
            target = new AreaProgress { areaId = area.areaId };
            data.areaProgress.Add(target);
        }

        mutation(target);
        RecalculateDerivedAreaTotals(data);
        p.RestoreFrom(data);
    }

    private void ChangeAreaCounter(AreaData area, string counter, int delta)
    {
        MutateArea(area, delegate(AreaProgress ap)
        {
            switch (counter)
            {
                case "runas": ap.runasFound = Mathf.Clamp(ap.runasFound + delta, 0, Mathf.Max(0, area.totalRunas)); break;
                case "npcs": ap.npcsRescued = Mathf.Clamp(ap.npcsRescued + delta, 0, Mathf.Max(0, area.totalNpcsToRescue)); break;
                case "whispers": ap.whispersFound = Mathf.Clamp(ap.whispersFound + delta, 0, Mathf.Max(0, area.totalWhispers)); break;
                case "delivered": ap.whispersDelivered = Mathf.Clamp(ap.whispersDelivered + delta, 0, Mathf.Max(0, area.totalWhispers)); break;
                case "chests": ap.chestsFound = Mathf.Clamp(ap.chestsFound + delta, 0, Mathf.Max(0, area.totalChests)); break;
                case "fragments": ap.fragmentsFound = Mathf.Clamp(ap.fragmentsFound + delta, 0, Mathf.Max(0, area.totalFragments)); break;
            }
        });
    }

    private void CompleteAreaDiscoveries(AreaData area)
    {
        MutateArea(area, delegate(AreaProgress ap)
        {
            ap.opened = true;
            ap.visited = true;
            ap.runasFound = Mathf.Max(0, area.totalRunas);
            ap.npcsRescued = Mathf.Max(0, area.totalNpcsToRescue);
            ap.whispersFound = Mathf.Max(0, area.totalWhispers);
            ap.whispersDelivered = Mathf.Max(0, area.totalWhispers);
            ap.chestsFound = Mathf.Max(0, area.totalChests);
            ap.fragmentsFound = Mathf.Max(0, area.totalFragments);
            // challengeDiscovered/challengeCompleted ficam intocados de propósito.
        });

        if (area.freedAnimalForm != null) FreeAnimal(area.freedAnimalForm);
        SetStatus($"Descobertas de {area.displayName} completadas; desafio não alterado.");
    }

    private void ResetAreaDiscoveries(AreaData area)
    {
        MutateArea(area, delegate(AreaProgress ap)
        {
            ap.opened = false;
            ap.visited = false;
            ap.deaths = 0;
            ap.runasFound = 0;
            ap.npcsRescued = 0;
            ap.whispersFound = 0;
            ap.whispersDelivered = 0;
            ap.chestsFound = 0;
            ap.fragmentsFound = 0;
            ap.sussurrosDaTerraOuvidos.Clear();
            // challengeDiscovered/challengeCompleted ficam intocados de propósito.
        });
        SetStatus($"Descobertas de {area.displayName} resetadas; desafio não alterado.");
    }

    private void RecalculateDerivedAreaTotals(SaveData data)
    {
        if (data == null || data.areaProgress == null) return;

        int whispers = 0;
        int chests = 0;
        foreach (var ap in data.areaProgress)
        {
            if (ap == null) continue;
            whispers += Mathf.Max(0, ap.whispersFound);
            chests += Mathf.Max(0, ap.chestsFound);
        }

        data.totalSussurrosCollected = whispers;
        data.totalChestsOpenedGlobal = chests;
    }

