    private int GetSpawnSelection(AreaData area, int count)
    {
        if (area == null || count <= 0) return 0;
        int value;
        if (!_spawnSelection.TryGetValue(area.areaId, out value)) value = 0;
        value = Mathf.Clamp(value, 0, count - 1);
        _spawnSelection[area.areaId] = value;
        return value;
    }

    private void SetSpawnSelection(AreaData area, int value, int count)
    {
        if (area == null || count <= 0) return;
        if (value < 0) value = count - 1;
        if (value >= count) value = 0;
        _spawnSelection[area.areaId] = value;
    }

    private void TravelToArea(AreaData area, string spawnId)
    {
        if (area == null || AreaManager.Instance == null || SceneLoader.Instance == null || LoadingScreenController.Instance == null)
        {
            SetStatus("Transporte indisponível: verifica AreaManager, SceneLoader e LoadingScreenController.");
            return;
        }

        if (string.IsNullOrWhiteSpace(area.sceneName) || !Application.CanStreamedLevelBeLoaded(area.sceneName))
        {
            SetStatus("A cena da área não está configurada no Build Settings.");
            return;
        }

        if (AreaManager.Instance.TransitionPending)
        {
            SetStatus("Já existe uma transição em andamento.");
            return;
        }

        if (string.IsNullOrEmpty(spawnId))
        {
            _pendingFallbackScene = area.sceneName;
            SceneManager.sceneLoaded -= HandleFallbackSpawnAfterTravel;
            SceneManager.sceneLoaded += HandleFallbackSpawnAfterTravel;
        }

        SetOpen(false);
        AreaManager.Instance.RequestTransition(area, spawnId);
    }

    private void HandleFallbackSpawnAfterTravel(Scene scene, LoadSceneMode mode)
    {
        if (string.IsNullOrEmpty(_pendingFallbackScene) || scene.name != _pendingFallbackScene) return;

        SceneManager.sceneLoaded -= HandleFallbackSpawnAfterTravel;
        _pendingFallbackScene = null;

        var points = FindObjectsOfType<AreaSpawnPoint>();
        if (points == null || points.Length == 0)
        {
            Debug.LogWarning("[AnimalsDebugPanel] A área não tem AreaSpawnPoint. O player manteve a posição anterior.");
            return;
        }

        var player = FindPlayer();
        if (player == null) return;

        var rb = player.GetComponent<Rigidbody2D>();
        if (rb != null)
        {
            rb.position = points[0].transform.position;
            rb.velocity = Vector2.zero;
        }
        else
        {
            player.transform.position = points[0].transform.position;
        }
    }

