    private void CreateOrSetVariable()
    {
        var vars = GameVariables.Instance;
        string name = (_newVariableName ?? "").Trim();
        if (vars == null || string.IsNullOrEmpty(name))
        {
            SetStatus("Define um nome de variável.");
            return;
        }

        string value = _newVariableValue ?? "";
        switch ((VariableType)_newVariableType)
        {
            case VariableType.Bool:
                bool boolValue;
                if (!bool.TryParse(value, out boolValue))
                {
                    SetStatus("Bool inválido. Usa true ou false.");
                    return;
                }
                vars.SetBool(name, boolValue);
                break;

            case VariableType.Int:
                int intValue;
                if (!int.TryParse(value, out intValue))
                {
                    SetStatus("Int inválido.");
                    return;
                }
                vars.SetInt(name, intValue);
                break;

            case VariableType.Float:
                float floatValue;
                string normalised = value.Replace(',', '.');
                if (!float.TryParse(normalised, System.Globalization.NumberStyles.Float, System.Globalization.CultureInfo.InvariantCulture, out floatValue))
                {
                    SetStatus("Float inválido.");
                    return;
                }
                vars.SetFloat(name, floatValue);
                break;

            case VariableType.String:
                vars.SetString(name, value);
                break;
        }

        SetStatus($"Variável '{name}' definida.");
    }

