    private void ApplyGodModeToCurrentPlayer(bool enabled)
    {
        var player = FindPlayer();
        if (player == null) return;

        var combat = player.GetComponent<PlayerCombat>();
        if (combat == null) return;

        foreach (DamageType type in Enum.GetValues(typeof(DamageType)))
            combat.GrantTemporaryImmunity(type, enabled ? 86400f : 0f);

        if (enabled && PlayerProgress.Instance != null && PlayerProgress.Instance.currentHearts <= 0)
            PlayerProgress.Instance.Heal(PlayerProgress.Instance.maxHearts);
    }

    private void SetTransformCheat(bool enabled)
    {
        _transformCheat = enabled;

        if (enabled)
        {
            ApplyTransformCheatToCurrentPlayer();
            SetStatus("Transformação livre ligada: sem exigência de chão e sem cooldown.");
        }
        else
        {
            RestoreTransformDefaults();
            SetStatus("Regras normais de transformação restauradas.");
        }
    }

    private void ApplyTransformCheatToCurrentPlayer()
    {
        var fs = FindFormSwitcher();
        if (fs == null) return;

        if (!_transformDefaultsCaptured)
        {
            _originalRequireGrounded = fs.requireGrounded;
            _originalTransformCooldown = fs.transformCooldown;
            _transformDefaultsCaptured = true;
        }

        fs.requireGrounded = false;
        fs.transformCooldown = 0f;
    }

    private void RestoreTransformDefaults()
    {
        if (!_transformDefaultsCaptured) return;

        var fs = FindFormSwitcher();
        if (fs != null)
        {
            fs.requireGrounded = _originalRequireGrounded;
            fs.transformCooldown = _originalTransformCooldown;
        }

        _transformDefaultsCaptured = false;
        _transformCheat = false;
    }

