    private T FindPlayerComponent<T>() where T : Component
    {
        var player = FindPlayer();
        return player != null ? player.GetComponent<T>() : null;
    }

    private GameObject FindPlayer()
    {
        try
        {
            return GameObject.FindGameObjectWithTag("Player");
        }
        catch (UnityException)
        {
            return null;
        }
    }

    private void TeleportPlayerTo(Vector3 position)
    {
        var player = FindPlayer();
        if (player == null)
        {
            SetStatus("Player com tag 'Player' não encontrado.");
            return;
        }

        var target = position + Vector3.up * 1.5f;
        var rb = player.GetComponent<Rigidbody2D>();
        if (rb != null)
        {
            rb.position = target;
            rb.velocity = Vector2.zero;
        }
        else
        {
            player.transform.position = target;
        }
    }

    private bool Matches(params string[] values)
    {
        if (string.IsNullOrWhiteSpace(_search)) return true;
        string needle = _search.Trim().ToLowerInvariant();
        foreach (var value in values)
        {
            if (!string.IsNullOrEmpty(value) && value.ToLowerInvariant().Contains(needle)) return true;
        }
        return false;
    }

