    private void DrawDangerConfirmation()
    {
        if (_pendingDangerAction == null) return;

        GUILayout.BeginVertical(GUI.skin.box);
        GUILayout.Label("⚠ " + _pendingDangerLabel, _dangerStyle);
        GUILayout.BeginHorizontal();
        if (GUILayout.Button("Cancelar"))
        {
            _pendingDangerAction = null;
            _pendingDangerLabel = null;
        }
        if (GUILayout.Button("Confirmar"))
        {
            var action = _pendingDangerAction;
            _pendingDangerAction = null;
            _pendingDangerLabel = null;
            action?.Invoke();
        }
        GUILayout.EndHorizontal();
        GUILayout.EndVertical();
    }
}
